struct DSU {
    parent: Vec<i64>,
    // diff[i] stores the parity distance (0 or 1) from node i to its parent[i]
    diff: Vec<i64>,
}

impl DSU {
    fn new(n: i64) -> DSU {
        let n_usize = n as usize;
        DSU {
            parent: (0..n).collect(),
            diff: vec![0; n_usize],
        }
    }

    // Finds the root of i and returns (root, parity_distance_to_root).
    fn find(&mut self, i: i64) -> (i64, i64) {
        let i_usize = i as usize;

        if self.parent[i_usize] == i {
            return (i, 0);
        }

        // Recursive call to find root and get distance from parent to root
        let (root, root_diff) = self.find(self.parent[i_usize]);

        // Path compression and diff update:
        // New distance from i to root = (old distance i -> parent) XOR (distance parent -> root)
        self.diff[i_usize] ^= root_diff;
        self.parent[i_usize] = root;

        (root, self.diff[i_usize])
    }

    // Processes edge (u, v) with weight w. Returns true if the edge is added.
    fn unite(&mut self, u: i64, v: i64, w: i64) -> bool {
        // Find roots and distances
        let (root_u, dist_u) = self.find(u);
        let (root_v, dist_v) = self.find(v);

        if root_u != root_v {
            // Case 1: Different components. Edge is always added.

            // Merge root_u into root_v.
            self.parent[root_u as usize] = root_v;

            // Calculate the required distance from root_u to root_v:
            // d(root_u, root_v) = d(root_u, u) XOR w XOR d(v, root_v)
            // d(root_u, u) = dist_u
            // d(v, root_v) = dist_v
            self.diff[root_u as usize] = dist_u ^ w ^ dist_v;

            true
        } else {
            // Case 2: Same component. Check cycle parity.
            // Path parity in existing graph: d(u, v) = d(u, root) XOR d(v, root)
            let path_parity = dist_u ^ dist_v;

            // Cycle parity: path_parity XOR w
            let cycle_parity = path_parity ^ w;

            // Edge is added only if cycle_parity is 0 (even weight).
            cycle_parity == 0
        }
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let mut dsu = DSU::new(n);
    let mut added_edges_count = 0;

    for edge in edges {
        // edge = [u, v, w]
        let u = edge[0];
        let v = edge[1];
        let w = edge[2];

        if dsu.unite(u, v, w) {
            added_edges_count += 1;
        }
    }

    added_edges_count
}

