struct DSU {
    parent: Vec<i64>,
    diff: Vec<i64>, // Stores parity difference (0 or 1) from node to its parent
    size: Vec<i64>, // For union by size optimization
}

impl DSU {
    fn new(n: i64) -> Self {
        let n_usize = n as usize;
        DSU {
            parent: (0..n).collect(),
            diff: vec![0; n_usize],
            size: vec![1; n_usize],
        }
    }

    // Finds the root and returns (root, distance_to_root_parity)
    // Implements path compression and updates diff[] along the path.
    fn find(&mut self, i: i64) -> (i64, i64) {
        let i_usize = i as usize;

        if self.parent[i_usize] == i {
            return (i, 0);
        }

        // Recursive find with path compression
        let (root, root_diff) = self.find(self.parent[i_usize]);

        // Update diff[i]: d(i, root) = d(i, parent) + d(parent, root) mod 2
        self.diff[i_usize] ^= root_diff;
        self.parent[i_usize] = root;

        (root, self.diff[i_usize])
    }

    // Processes edge (u, v, w). Returns true if accepted, false otherwise.
    fn union(&mut self, u: i64, v: i64, w: i64) -> bool {
        // Find roots and path parities relative to roots
        let (root_u, diff_u) = self.find(u);
        let (root_v, diff_v) = self.find(v);

        if root_u != root_v {
            // Case 1: Different components. Merge them.

            let u_idx = root_u as usize;
            let v_idx = root_v as usize;

            // Determine merge direction based on size
            let (parent_root, child_root, diff_parent_to_child) = if self.size[u_idx] >= self.size[v_idx] {
                // Root U becomes parent of Root V
                // Target diff[R_v] = d(R_v, R_u) = d(R_v, v) ^ w ^ d(u, R_u)
                // d(R_v, v) = diff_v (path v -> R_v)
                // d(u, R_u) = diff_u (path u -> R_u)
                (root_u, root_v, diff_u ^ w ^ diff_v)
            } else {
                // Root V becomes parent of Root U
                // Target diff[R_u] = d(R_u, R_v) = d(R_u, u) ^ w ^ d(v, R_v)
                // d(R_u, u) = diff_u (path u -> R_u)
                // d(v, R_v) = diff_v (path v -> R_v)
                (root_v, root_u, diff_u ^ w ^ diff_v)
            };

            // Perform union
            self.parent[child_root as usize] = parent_root;
            self.diff[child_root as usize] = diff_parent_to_child;
            self.size[parent_root as usize] += self.size[child_root as usize];

            return true;
        } else {
            // Case 2: Same component. Check cycle condition.
            // Existing path parity P_uv = diff_u ^ diff_v
            // Cycle weight parity = w + P_uv
            let existing_path_parity = diff_u ^ diff_v;

            // Accept if cycle weight is even, i.e., w == existing_path_parity
            return (w % 2) == existing_path_parity;
        }
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let mut dsu = DSU::new(n);
    let mut accepted_edges_count = 0;

    for edge in edges {
        let u = edge[0];
        let v = edge[1];
        let w = edge[2];

        if dsu.union(u, v, w) {
            accepted_edges_count += 1;
        }
    }

    accepted_edges_count
}

